// Parse WTTJ alert email HTML and extract job listings
// Then auto-tag by location: Remote or DMV area → "Relevant", otherwise → "Skip"
const items = [];

// DMV area keywords (DC, Maryland, Virginia metro area)
const DMV_KEYWORDS = [
  'washington', 'dc', 'd.c.', 'district of columbia',
  'maryland', 'virginia',
  'arlington', 'alexandria', 'fairfax', 'reston', 'tysons',
  'mclean', 'herndon', 'sterling', 'ashburn', 'leesburg',
  'bethesda', 'rockville', 'silver spring', 'college park',
  'columbia', 'baltimore', 'annapolis',
  'dmv'
];

const REMOTE_KEYWORDS = [
  'remote', 'full remote', 'full-remote', 'fully remote',
  'work from home', 'wfh', 'anywhere', 'distributed'
];

function classifyLocation(location) {
  if (!location) return 'Skip';
  const loc = location.toLowerCase();

  // Check for remote
  for (const kw of REMOTE_KEYWORDS) {
    if (loc.includes(kw)) return 'Relevant';
  }

  // Check for DMV area
  for (const kw of DMV_KEYWORDS) {
    if (loc.includes(kw)) return 'Relevant';
  }

  return 'Skip';
}

for (const item of $input.all()) {
  let html = '';
  const json = item.json;

  // Extract HTML body from Gmail API response
  if (json.payload) {
    if (json.payload.body && json.payload.body.data) {
      html = Buffer.from(json.payload.body.data, 'base64').toString('utf-8');
    } else if (json.payload.parts) {
      for (const part of json.payload.parts) {
        if (part.mimeType === 'text/html' && part.body && part.body.data) {
          html = Buffer.from(part.body.data, 'base64').toString('utf-8');
          break;
        }
      }
    }
  }
  if (!html) html = json.html || json.textHtml || json.body || '';

  // Parse date
  const receivedDate = json.internalDate || json.date || new Date().toISOString();
  let dateStr;
  if (/^\d{13}$/.test(String(receivedDate))) {
    dateStr = new Date(parseInt(receivedDate)).toISOString().split('T')[0];
  } else {
    dateStr = new Date(receivedDate).toISOString().split('T')[0];
  }

  if (!html) {
    items.push({
      json: {
        'Date Received': dateStr,
        'Company': '⚠ NO HTML BODY',
        'Job Title': 'Email body not found. Keys: ' + Object.keys(json).join(', '),
        'URL': '', 'Location': '', 'Salary': '', 'Status': 'Error'
      }
    });
    continue;
  }

  // Each job card is in a <tbody class="greyHover"> block
  const jobBlocks = html.split('greyHover');

  for (let i = 1; i < jobBlocks.length; i++) {
    const block = jobBlocks[i];

    // Extract company name from logo alt text: alt="CompanyName logo"
    const logoAltMatch = block.match(/alt="([^"]+?)\s+logo"/i);
    const company = logoAltMatch ? logoAltMatch[1].trim() : '';

    // Skip non-job blocks and the header WTTJ logo
    if (!company) continue;
    if (company.toLowerCase().includes('welcome to the jungle')) continue;

    // Extract the tracking URL from the <a> tag before this block
    const prevBlock = jobBlocks[i - 1];
    const allHrefs = [...(prevBlock.matchAll(/href="(https?:[^"]+)"/g))];
    let trackingUrl = '';
    if (allHrefs.length > 0) {
      trackingUrl = allHrefs[allHrefs.length - 1][1];
    }

    // Extract job title from <strong> tags
    const strongRegex = /<strong>\s*([\s\S]*?)\s*<\/strong>/g;
    let jobTitle = '';
    let strongMatch;
    while ((strongMatch = strongRegex.exec(block)) !== null) {
      const text = strongMatch[1]
        .replace(/<[^>]+>/g, '')
        .replace(/\s+/g, ' ')
        .trim();
      if (text && text !== company) {
        jobTitle = text;
        break;
      }
    }

    // Extract salary and location from <em> tag
    // HTML structure: <em>Salary: $X-YK<br>Location Name</em>
    const emMatch = block.match(/<em[^>]*>([\s\S]*?)<\/em>/i);
    let location = '';
    let salary = '';
    if (emMatch) {
      // Split on <br> tags to separate lines, THEN clean HTML
      const rawLines = emMatch[1].split(/<br\s*\/?>/i);
      for (const rawLine of rawLines) {
        const line = rawLine
          .replace(/<[^>]+>/g, '')
          .replace(/&nbsp;/g, ' ')
          .replace(/\s+/g, ' ')
          .trim();
        if (!line) continue;
        if (line.match(/\$[\d,.]+/) || line.match(/salary/i)) {
          salary = line;
        } else if (line.length > 1) {
          location = line;
        }
      }
    }

    // Auto-classify: Remote or DMV → Relevant, otherwise → Skip
    const status = classifyLocation(location);

    items.push({
      json: {
        'Date Received': dateStr,
        'Company': company,
        'Job Title': jobTitle,
        'URL': trackingUrl,
        'Location': location,
        'Salary': salary,
        'Status': status
      }
    });
  }
}

if (items.length === 0) {
  items.push({
    json: {
      'Date Received': new Date().toISOString().split('T')[0],
      'Company': '⚠ NO JOBS PARSED',
      'Job Title': 'Check email format',
      'URL': '', 'Location': '', 'Salary': '', 'Status': 'Error'
    }
  });
}

return items;
